    background-image: url('https://files.catbox.moe/3ansl3.png');
}



/* 右侧导航图标 */
#rightNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/kkwv8e.png');
}





/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/9c4znj.png') center/contain no-repeat !important;
  width: 34px !important;
  height: 35px !important;

}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/8rodxv.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-top: 1px !important;
}

/* 发送按钮 */
.fa-paper-plane {
  background: url('https://files.catbox.moe/flfdmt.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-left: 1px !important;

}


/* Font Awesome类图标 */
.fa-bars::before,           
.fa-ellipsis-v::before,     
.fa-paper-plane::before,     
#extensionsMenuButton::before {  
  display: none !important;
  content: '' !important;  
}


   body.no-blur #top-bar {
    box-shadow: none;
  }

#send_form:hover #qr--bar {    height: 40px;    transition: all 0.5s ease;}#qr--bar {    height: 0.1px;}


/* 错误 */
div.toast.toast-error {

  top: 10px !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  margin: 0 !important;
  z-index: 1001 !important;
  width: 340px;
  min-height: 50px;


  background-image: 
  url('https://files.catbox.moe/f66bdv.jpg') !important;
  background-color: rgba(212,224,255,0.8) !important; 
  border-radius: var(--ui-border-radius) !important;


  padding-left: 70px !important; 
  overflow: visible !important;


  color: var(--theme-pink-accent) !important;
  text-shadow: 1px 1px 3px rgba(255, 255, 255, 0.7) !important;
  border: 1px solid var(--theme-border) !important;
  border-radius: var(--ui-border-radius) !important;
  box-shadow: 0 4px 12px rgba(100, 100, 100, 0.25) !important;
}


div.toast.toast-error {
  border-radius: 10px !important; 
}


div.toast.toast-error::before {
  content: "";
  position: absolute;
  left: -5px; 
  top: 50%;
  transform: translateY(-50%);
  width: 70px;
  height: 70px;
  background: url('https://files.catbox.moe/4zbuvg.png') center center / contain no-repeat;
  z-index: 1002; 
  filter: drop-shadow(2px 2px 4px rgba(0,0,0,0.1));
  animation: decorFloat 3s ease-in-out infinite;
}





/* 正确 */
div.toast.toast-success {
  top: 10px !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  margin: 0 !important;
  z-index: 1001 !important;
  width: 340px;
  min-height: 50px;

  background-image: 
  url('https://files.catbox.moe/f66bdv.jpg') !important; 
  background-color: rgba(236, 255, 223, 0.9) !important; 
  border-radius: var(--ui-border-radius) !important;

  padding-left: 70px !important;
  overflow: visible !important;

  color: #535E4C !important; /* 亮文字 */
  text-shadow: 1px 1px 3px rgba(255, 255, 255, 0.7) !important;
  border: 1px solid #8BA379 !important; /* 边框 */
  box-shadow: 0 4px 12px rgba(46, 204, 113, 0.25) !important; /* 投影 */
}

div.toast.toast-success {
  border-radius: 10px !important; 
}



div.toast.toast-success::before {
  content: "";
  position: absolute;
  left: -5px; 
  top: 50%;
  transform: translateY(-50%);
  width: 80px;
  height: 80px;
  background: url('https://files.catbox.moe/5myc1d.png') center center / contain no-repeat;
  z-index: 1002; 
  filter: drop-shadow(2px 2px 4px rgba(0,0,0,0.1));
  animation: decorFloat 3s ease-in-out infinite;
}
